/**
 * This is the main entry point for the debug module.
 * It detects the current environment (Node.js or browser) and loads the appropriate implementation.
 * 
 * The debug module is a dependency of Express.js and is used for internal logging.
 * This file acts as a switchboard to route debug calls to either the Node.js or browser implementation.
 */

/**
 * Detect if we're in a browser environment or Node.js environment.
 * This determines which implementation to load.
 */
if (typeof process !== 'undefined' && process.type === 'renderer') {
  // Electron renderer process
  module.exports = require('./browser.js');
} else if (typeof process !== 'undefined' && typeof process.versions === 'object' && typeof process.versions.node !== 'undefined') {
  // Node.js environment
  module.exports = require('./node.js');
} else {
  // Browser environment
  module.exports = require('./browser.js');
}